var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"콜록 콜록- 성공한 건가?","JPN":"ゲホ、ゲホ……成功したのか？","ENG":"*Cough!* *Cough!* Did it work?","TWN":"咳咳，咳咳- 成功降落嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"으윽… 충격으로 머리를 부딪힌 것 같은데.","JPN":"ううっ……衝撃で頭をぶつけたみたいだな。","ENG":"Urgh... I think I bumped my head.","TWN":"呃…剛剛衝擊太大，害我好像撞到頭咧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어이, 네놈이 만들었다는 탈출장치. 제대로 작동한 거 맞아?","JPN":"おい、てめえが作ったという脱出装置。ちゃんと作動したのか？","ENG":"Hey, that escape pod that you made. Are you sure it worked?","TWN":"喂，這是你們做的逃生裝置，確定有正常運作吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그 끈질긴 우주경찰 놈들에게서 도망칠 방법이 있다더니, 날 대체 어디로 데려온 것이냐?","JPN":"あのしつこい宇宙警察の奴らから逃げる方法があると言っていたが、いったいどこへ連れて来たのだ？","ENG":"You told me that there is a way to run away from those tedious space cops, but where have you brought me to?","TWN":"說什麼有辦法可以躲避那些難纏的宇宙警察，結果到底把我帶到什麼地方來啦？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"나도 몰라. 급하게 가동하느라 좌표를 설정할 시간도 없었으니까.","JPN":"俺にもわからないな。急いで起動させたせいで、座標を設定する時間すらなかった。","ENG":"I don’t know. I was rushing so much, I didn’t have time to set the coordinates.","TWN":"我也不知道，剛剛啟動的時候情況很緊急，根本來不及設定座標。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"킁킁, 어디서 탄내가 나는데?","JPN":"クンクン、どこかで焦げた匂いがするが？","ENG":"*Sniff, sniff* Something’s burning.","TWN":"嗅嗅，哪來的味道？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아, 망할놈의 워프 장치가 또 고장 났군.","JPN":"あーあ、ポンコツワープ装置がまた壊れやがった。","ENG":"Oh, the damn warp machine is broken again.","TWN":"可惡，這個爛東西的控制裝置又壞了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭣?! 그럼 돌아갈 방법이 없다는 거야?","JPN":"はあ！？　となると、戻る方法がないのか？","ENG":"What?! Does that mean that there’s no way of going back?","TWN":"什麼？！我們沒辦法回去的意思嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"고작 한 번 사용한 걸로 망가지다니. 하여간 고철을 좋아하는 것 치고 제대로 완성할 줄 아는 것이 없구나.","JPN":"一度使ったくらいで壊れるとは。まったく、くず鉄好きの割にまともなものは作れんのだな。","ENG":"Breaking down after a single use? Should've known better from a junk collector like you.","TWN":"才用一次就壞掉，說什麼喜歡廢鐵，結果根本一點辦法也沒有。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아아, 뭐가 이렇게 잔말들이 많아? 싫으면 거기 남아서 정의집행이나 당하시던가.","JPN":"ああ、ごちゃごちゃうるさい。イヤならそこに残って警察につかまったらどうだ？","ENG":"Stop complaining! You could've just stayed and let justice be served upon your pathetic selves.","TWN":"喂喂，廢話那麼多，有意見的話你們怎麼不留在那直接被原地逮捕？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"그러고보니 그 강소영이란 우주경찰 녀석, 널 보면서 만년 묵은 뱀으로 술을 담그면 기가 막히겠다고 했었지 아마?","JPN":"そういえばあのマエカワ・ナツミという宇宙警察、お前を見ながら一万年生きた蛇で作った酒はうまそうだとか言ってたよな？","ENG":"Come to think of it, that space cop named Kang Soyoung... She said something about brewing liquor with a snake that’s old as time itself, no?","TWN":"話說回來，那個叫姜素英的宇宙警察應該是說要把你抓去泡蛇酒喝掉吧？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"아직도 생각만 하면 소름이 끼치는군.","JPN":"いまだに思い出すだけでぞっとする。","ENG":"I still get goosebumps when I think about it.","TWN":"想到我就頭皮發麻。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"난 인간의 마음을 읽을 줄 알지만… 그 눈빛은 진심이었어.","JPN":"我は人間の心を読むことができるが……あの目は本気であった。","ENG":"I can read human minds... And she wasn’t joking when she said it.","TWN":"雖然我會讀人類的心思…但她的眼神，是認真的。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"하아, 배고프구만. 난 밥이나 먹으러 가련다.","JPN":"はあ、腹減ったなあ。アタシは飯でも食いに行くぞ。","ENG":"*Sigh...* I’m hungry. Might as well get something to eat.","TWN":"唉唷，肚子好餓，我要去找東西吃。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"무식한 녀석이 팔자걱정도 없구나. 여기가 어딘 줄 알고 함부로 발길을 옮기는 것이냐?","JPN":"愚か者は先の心配もないのだな。ここがどこかもわからないのにむやみに動くつもりなのか？","ENG":"Look who’s making herself at home already. You don’t even know the area here!","TWN":"頭腦簡單的傢伙果然是天不怕地不怕。你以為這裡是哪裡，竟然敢輕易移動腳步？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"우리가 살던 동네랑 별 차이 없어 보이는데, 아무 식당이나 들어가면 되는 거 아닌가?","JPN":"アタシたちが住んでいた街とあんま変わんないようだけど、適当にどこかの店に入ればいいんじゃないか？","ENG":"It doesn’t look that different from our side of town. Just get inside any restaurant.","TWN":"這裡看起來跟我們住的地方附近差不多啊，不是隨便找間餐廳進去就好嗎？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"어리석군. 언제 어디서 우주경찰 녀석들이 다시 나타날지도 모르는데…","JPN":"愚かな。いつどこから宇宙警察がまた現れるやも知れぬというのに……","ENG":"Fool. Those space cops could barge in any second...","TWN":"蠢東西，宇宙警察不知道什麼時候又會冒出來…"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"같이 가자. 대충 끼니 때우고 주변 좀 둘러봐야겠네.","JPN":"一緒に行こう。適当に食事でもして周りを見回ってみる。","ENG":"Take me with you. I should look around after getting some food.","TWN":"一起去吧，先吃點東西再觀察一下周圍。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"뭣…?","JPN":"何……？","ENG":"What...?","TWN":"什麼…？"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"이놈들…! 날 혼자 두고 어딜 가는 것이냐!","JPN":"こやつら……！　我を一人残してどこへ行くのだ！","ENG":"You idiots...! Don’t leave me here alone!","TWN":"你們二個…！是要扔下我去哪！"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"아아, 간만에 배부르게 먹었네.","JPN":"ああ、久々に腹いっぱい食ったな。","ENG":"Aah, now that’s what I call a good meal.","TWN":"噢～好久沒吃這麼飽咧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"이쪽 세계도 제법 요리 수준이 괜찮군.","JPN":"こっちの世界も料理はなかなかだな。","ENG":"The culinary industry in this world isn’t so bad after all.","TWN":"看來這個世界的東西也蠻不錯吃的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"그렇죠? 얼마 전에 유미나란 분이 다녀가신 뒤로 저희 세상에도 맛있는 요리들이 엄~청 많아졌다고요.","JPN":"ですよね？　この前ヤナギ・ミナって人が立ち寄ってから、僕たちの世界にも美味しい料理がすごく増えたんですよ。","ENG":"Indeed! There have been tons of improvements in our cuisine after a foreigner called Yoo Mina visited.","TWN":"是不是？之前有個叫劉米娜的人來過後，我們的世界好吃的東西就變超～多的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SORIM_NPC_FOOLSDAY_NULL","text":{"KOREA":"치킨도, 탕수육도, 전부 그 사람에게 만드는 법을 전수받았다. 우리 직장에선 그녀를 영웅으로 추앙하고 있지.","JPN":"チキンも、酢豚も、全部あの人から作り方を教えてもらった。職場ではみんな彼女を英雄と仰いでる。","ENG":"Fried Chicken, Sweet and Sour Pork... Many things we learned from her. We honor her as a hero in our company.","TWN":"炸雞和糖醋肉都是跟那個人學的，在我們業界裡都把她奉為英雄欸。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HARIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SORIM_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭣? 고작 한 사람이 그 엄청난 메뉴들을 전부 개발했다고? 그 녀석… 신이냐?!","JPN":"は？　たった一人であの数のメニューを全部開発しただって？　そいつ……神かよ！？","ENG":"What? All those recipes from a single person? Is she... a god?","TWN":"什麼？這麼厲害的菜單都是她一個人開發的嗎？那傢伙…是神嗎？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아무래도, 다른 세계선에서 이쪽을 다녀간 게 우리가 처음이 아닌 모양이군.","JPN":"どうやら他の世界線からこっちに立ち寄ったのは俺たちが最初じゃないようだな。","ENG":"It sounds like we’re not the first ones to stumble upon this universe.","TWN":"看來我們並不是第一個從其他世界來到這裡的人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"다시 돌아갈 방법을 의외로 쉽게 찾을지도 모르겠어.","JPN":"戻る方法は意外と簡単に見つかるかもしれない。","ENG":"Perhaps it wouldn’t be so hard to find out a way to go back after all.","TWN":"或許回去的方法比想像中還容易找到呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"남는 게 시간인데 급할 필요 없지. 그 우주경찰 녀석들이 늙어 죽을 때까지 잠시 여기 머무르는 것도 나쁘지 않겠구나.","JPN":"時間なら有り余っている、急ぐ必要はなかろう。あの宇宙警察のやつらが老いて死ぬまでしばらくここに留まるのも悪くないな。","ENG":"No need to rush. We have all the time we need. It wouldn’t be so bad staying here for a while, until those mortal space cops grow old and die.","TWN":"接下來就是時間問題，不需要著急。在那個宇宙警察老死前，暫時留在這裡好像也不錯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"웃기지 마. 우리가 너처럼 천년만년 사는 이무긴 줄 알아?","JPN":"ふざけるな。俺らがお前のように千年も万年も生きられる大蛇だと思ってるのか？","ENG":"You’ve got to be kidding me. Not everyone is a half-immortal serpent like you.","TWN":"說什麼笑話，你以為我們跟你這條蟒蛇一樣可以活到千萬年嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"뭣이? 이무기…?! 날 그런 저급한 존재와 비교하다니…","JPN":"何？　大蛇……！？　我をあんな下等な存在と比べるとは……","ENG":"Serpent, you say? How dare you compare me with such a lowly being?","TWN":"什麼？蟒蛇…？！竟然拿那種低賤的東西來跟我比較…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그런데 오로치, 넌 아까부터 뭘 마시고 있는 거야? 좀전까지 음식에 독이 들었을 지 모른다며 온갖 호들갑을 떨더니만.","JPN":"てかオロチ、てめえさっきから何飲んでんだ？　ちょっと前までは食べ物に毒が入ってるかもしれないって騒いでたくせに。","ENG":"Orochi, what is it that you’re drinking? You’re the one who went paranoid about the food being poisoned.","TWN":"大蛇，你是在喝什麼？你剛不是還在那邊說什麼食物可能會有毒嗎？　"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"버블티라는 것이다. 양서류의 알 같은 것이 잔뜩 들어있길래 주문했다만, 의외로 쫄깃한 떡 맛이 나더구나.","JPN":"タピオカティーというものだ。両生類の卵のようなものがぎっしり入っているから頼んでみたのだが、予想とは違ってモッチリとした餅の味だな。","ENG":"It’s called Bubble Tea. I ordered it because of its seemingly contained amphibian eggs, but they turned out to be a sort of chewy rice cake.","TWN":"說是珍珠奶茶，我看裡面好像有很多兩棲類的蛋才點的，結果口感反而是像年糕一樣QQ的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"네놈도 특별히 한 입 줄까?","JPN":"特別に貴様にも一口やろうか？","ENG":"I shall allow you to take a sip, if you wish.","TWN":"我特地允許你們喝一口看看，要嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"으윽, 누가 뱀여자 아니랄까봐. 그딴 표현을 써서 식욕이 뚝 떨어졌잖아.","JPN":"げっ、さすがヘビ女。そういうこと言うと食欲がなくなるだろ。","ENG":"Ugh, stop speaking, you serpent. Your word made me lose my appetite.","TWN":"呃，怕人家不知道你是蛇女嗎？被你說成那樣誰還想喝？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"쫄깃한 떡… 이라는 표현 말이냐?","JPN":"モッチリとした餅……という表現のことか？","ENG":"The chewy rice cake, you mean...?","TWN":"像年糕一樣QQ的…不行嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어이, 기계광. 혼자 어딜 가는 거야?","JPN":"おい、機械オタク。一人でどこ行くんだ？","ENG":"Hey, machine freak! Where do you think you’re going?","TWN":"喂，機械狂你是要去哪裡？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"워프가 고장 났으니 쓸만한 정비소를 찾아야지. 이 망할 수갑도 풀 겸.","JPN":"ワープが壊れたから適当な整備工場を探さないと。このウザい手錠も外さなきゃいけないし。","ENG":"With the warp machine broken, I have to look for a workshop that I could use... Maybe take off these darn handcuffs while I’m at it.","TWN":"控制裝置壞了當然要找看看有沒有維修站，順便也把這個礙事的手銬解開。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"내가 그 수갑 부숴줄까?","JPN":"その手錠、アタシが壊してやろうか？","ENG":"You want me to break them for you?","TWN":"還是我直接幫你把手銬弄壞？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"됐어. 힘조절 안 되는 녀석한테 내 손목을 맡기고 싶지 않아.","JPN":"いいよ。力加減もできないやつに手首を任せたくはない。","ENG":"Nope. I don’t feel comfortable trusting some lunatic like you who can’t control her own powers.","TWN":"不必，我不想把我的手腕交給一個不懂得拿捏力道的人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"저 녀석… 정말로 혼자 갔네.","JPN":"あいつ……マジで一人で行きやがった。","ENG":"That dummy... She really did go by herself.","TWN":"她…還真的給我自己去。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"잘 됐다. 어차피 기계는 알아서 고쳐질 테니 굳이 몰려다닐 필요는 없지.","JPN":"ちょうどいい。どうせ機械はやつが直すはずだから、群れる必要はあるまい。","ENG":"Even better. The machine will be fixed in time. There’s no point in moving as a group.","TWN":"有什麼關係？反正她自己會把東西修好，沒必要非得團體行動吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그나저나 저쪽에 오락실이라는 곳이 있던데, 무얼 하는지 구경이나 해보겠느냐?","JPN":"それよりあそこにゲームセンターというところがあるのだが、何をするところなのか見てみようではないか。","ENG":"Anyways, I saw an interesting place by the name of \\"arcade\\" over there. Would you like to see what it’s about?","TWN":"不過那邊好像有個叫遊戲場的地方，去看看那裡是在幹嘛的吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"아깐 함부로 움직이지 말자더니 금방 느슨해졌구만.","JPN":"さっきはむやみに動くなと言ったくせに、もう気を緩めるんだな。","ENG":"You scolded us to not go anywhere... But looks like you switched sides.","TWN":"剛剛是誰說不要輕易移動的，才過多久而已就忘啦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"이쪽 세계의 인간들은 전부 생긴 게 몽실몽실해서 딱히 위협이 될 것 같진 않더구나.","JPN":"この世界の人間はみなふっくらしていて、別に脅威的ではなさそうだった。","ENG":"The humans in this world look harmless. They’re all so plump.","TWN":"那是因為這個世界的人類全都長得圓圓的，感覺沒什麼威脅性。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"게다가…","JPN":"それに……","ENG":"Besides...","TWN":"而且…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"이 세계가 더 마음에 들게 된다면, 굳이 돌아가지 않고 우리가 이곳을 취하면 되지 않겠느냐?","JPN":"この世界が気に入ったなら、無理に帰らずに我々がここを占有してしまえばよかろう。","ENG":"If we come to favor this world, why not conquer it instead of going back?","TWN":"要是喜歡上這個世界的話，那也不是非回去不可，只需要把這個地方拿下不就好？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"큭큭, 벌써 여길 접수할 생각부터 하다니. 역시 현상수배 넘버 원은 수준이 다르구만.","JPN":"ククッ、すでにここをいただくつもりでいるとは。やっぱ指名手配ナンバー1はレベルが違うな。","ENG":"Hah hah, we just got here and you’re already thinking of taking over this world? I guess that’s what makes you most wanted","TWN":"呃，竟然已經想到要拿下這裡，頭號通緝犯的想法果然不一樣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그래. 덕분에 다시 떠올랐어. 우린 극악무도한 우주대악당이라는 걸.","JPN":"ああ。おかげで思い出したよ。アタシたちは極悪非道な宇宙大悪党だということをね。","ENG":"Yes. You reminded us that we are the Atrocious Space Supervillains.","TWN":"沒錯，拜你所賜我又再次想起來，我們可是十惡不赦的宇宙大反派欸！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"까짓 거 즐겨주지! 이세계 정복!","JPN":"楽しんでやろうじゃないか！　異世界征服！","ENG":"All right, let’s do it! Conquerors of this world!","TWN":"盡情享樂！征服世界！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"큿, 또 실패했잖아?","JPN":"くっ、また失敗か？","ENG":"Urgh, I failed again!","TWN":"可惡，又沒抓到！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_COMIC"},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"슬슬 포기하거라. 지금까지 헛돈만 날리고 있지 않느냐?","JPN":"そろそろ諦めるがよい。金の無駄使いではないか。","ENG":"It’s time you gave up. You are simply wasting money.","TWN":"你還是放棄吧，你這樣跟把錢扔水裡有什麼兩樣？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"시끄러! 난 내가 갖기로 한 건 무조건 갖는다!","JPN":"うるさい！　アタシは欲しいものは絶対手に入れる！","ENG":"Shut up! If I want something, I get it!","TWN":"不用你管！只要是我想要的東西，我就一定要得到！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그것 참 악당다운 대답이긴 하구나.","JPN":"非常に悪党らしい返事ではあるな。","ENG":"That sounds like a greedy villain indeed.","TWN":"這倒是很像反派會說的話。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그 갖고 싶다는 게 고작 뽑기인형이라는 것만 제외하면 말이지.","JPN":"その欲しいものがたかがクレーンゲームのぬいぐるみだということを除くけば。","ENG":"Disregarding the fact that what you want is a lousy plushie doll.","TWN":"雖然你想要的只是抓娃娃機裡的娃娃。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"고, 고작?! 인형을 갖고 싶어하면 악당이 아니라는 거냐?!","JPN":"た、たかが！？　ぬいぐるみを欲しがるやつは悪党じゃないってのか！？","ENG":"L-lousy?! Are you saying that villains aren't supposed to like dolls?","TWN":"只是？！你的意思是反派不能想要娃娃嗎？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그냥… 야생마처럼 생겨 먹은 네놈도 그런 면이 있다는 게 의외라서 말이다.","JPN":"ただ……野生馬のような貴様にそういう面があるということが意外でな。","ENG":"Rather... it’s that you don’t look like one to enjoy the dainty things in life.","TWN":"我只是…沒想到在你狂野不羈的形象之下，竟然有顆赤子之心。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"큭?! 거의 잡았었는데!","JPN":"くっ！？　もうちょっとで成功だったのに！","ENG":"Ngh?! I almost had it!","TWN":"呃？！差點就抓到咧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그런 나약한 집게로 인형을 집으려 애쓰다니, 규칙에 참으로 순종적이구나.","JPN":"そのように軟弱な道具でぬいぐるみを取ろうと躍起になるとは、実に規則に忠実なものだ。","ENG":"You seem very servile, trying to catch that thing with such a shabby claw.","TWN":"竟然這麼認真地用那個鬆鬆的爪子要抓娃娃，你還真是守規矩呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"뭐? 갑자기 그게 무슨 소리야?","JPN":"は？　いきなりなに言ってんだよ？","ENG":"What? What are you talking about?","TWN":"什麼意思？你在說什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"악당이면 악당답게, 집게로 인형을 뽑아야 한다는 인간들의 룰 따위는 부숴도 되지 않느냔 말이다.","JPN":"悪党なら悪党らしく、道具でぬいぐるみを取るという人間のルールなど、守らずともよいのではないか。","ENG":"You’re a villain. That alone is a reason to obtain what you want without abiding by the rules.","TWN":"我的意思是身為反派就要像個反派，用爪子抓娃娃是人類的規矩，反派何須遵守。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"어라? 그러고보니 내가 왜 정정당당하게 인형뽑기를 하고 있었지?","JPN":"あれ？　そういえばアタシはなんで正々堂々とクレーンゲームをしてるんだ？","ENG":"Huh? Come to think of it, why was I trying to get this fair and square?","TWN":"喔？聽你這麼一說，我幹嘛這麼乖，用這種正當方法在抓娃娃？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"좋아. 당장 안으로 가서 인형들 전부 꺼내 올 테니 거기서 누가 오는지 망 좀 보고 있으라고.","JPN":"よし。今すぐ中に入ってぬいぐるみを全部取って来るから、誰か来ないか見張ってな。","ENG":"All right. I’ll get inside and grab all of those dolls. You stay there and keep an eye on people, in case anyone walks over.","TWN":"好，我現在就進去把娃娃全都撈出來，你幫我把個風。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"쯧, 모양 떨어지게.","JPN":"ふん、みっともないことを。","ENG":"Tsk, how ungracious.","TWN":"嘖，看看你那什麼樣子。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"…빨리 끝내라.","JPN":"……早く終わらせるのだ。","ENG":"...You better hurry.","TWN":"…速戰速決。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"끄응… 조금만… 더 들어가면…!","JPN":"ぐぬぬ……もうちょっと……入れれば……！","ENG":"Ngh... Just a little more...!","TWN":"唔…只要…再進去一點…！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L39_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"됐다! 안까지 들어오는데 성공했어!","JPN":"よし！　中に入るまでは成功したぞ！","ENG":"I did it! I made it inside!","TWN":"終於！我終於爬到裡面啦！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm?","TWN":"嗯…？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L41_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"뭔가 심상치 않은 기운이 다가오고 있어. 숨어라.","JPN":"何か尋常でない気配が近づいてきている。隠れろ。","ENG":"I feel something sinister approaching. Hide.","TWN":"不太對勁，好像有什麼東西靠近，躲起來！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭣? 잠깐, 여기서 대체 어떻게 숨으라는 거야!","JPN":"は？　ちょ、ここでいったいどうやって隠れろっていうんだ！","ENG":"What? Wait, how do you expect me to hide in here?!","TWN":"什麼？拜託，這邊是要怎麼躲啦！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L44_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그거야 네놈이 알아서 잘 해야지.","JPN":"それは貴様が考えることだな。","ENG":"That’s up to you to figure out.","TWN":"那是你的問題，自己想辦法。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"야, 그걸 말이라고…!","JPN":"おい、冗談じゃ……！","ENG":"Hey, don’t be ridiculous...!","TWN":"喂，你說的是人話…！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흐음…? 뭐야, 이거?","JPN":"ふむ……？　何じゃ、これは？","ENG":"Hmm...? What is this?","TWN":"嗯…？什麼東東？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"낯선 그림체로군. 주인장이 이번에 새로 들여왔다는 인형인가?","JPN":"見慣れぬ絵柄じゃな。店主が今度新しく仕入れたというぬいぐるみか？","ENG":"It looks rather strange. Do you think it might be the new doll that came in?","TWN":"沒見過這種風格，是機台主人新進的娃娃嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어쩌지…? 이제 어떻게 하면 되는 거야?","JPN":"どうする……？　どうすればいいんだ？","ENG":"What do I do...? What do I do now?","TWN":"怎麼辦…？現在該怎麼辦才好？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"차라리 잘됐구나. 그대로 인형인 척해라.","JPN":"むしろ好都合。そのままぬいぐるみのふりをしてろ。","ENG":"Things turned out better than expected. Pretend that you’re a doll.","TWN":"這樣也好，你就乾脆假裝是娃娃吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"시종, 네가 이걸 한 번 뽑아보겠느냐?","JPN":"僕よ、其方がこれを引いてみるか？","ENG":"Why don’t you try to pull this one out, servant?","TWN":"僕人，這你抓得到嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"호오… 확실히 다른 인형보다 값어치는 있어보입니다만, 터무니없이 무거워 보이는군요.","JPN":"ほう……確かに他のぬいぐるみよりは値打ちはありそうですが、とてつもなく重そうですね。","ENG":"Hmm... It does look more valuable than the rest of the dolls. However, it also looks incredibly heavy.","TWN":"喔呵… 確實看起來比其他娃娃貴的感覺，可是重量感覺也不輕。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"값비싸기 때문에 이목을 끌지만 막상 얻는 것은 거의 불가능한, 전형적인 미끼 상품이죠.","JPN":"高値に見えて人目を引きますが、手に入れることは不可能に近い、典型的なおとり商品でございます。","ENG":"A typical bait prize, which looks flashy but is almost impossible to get.","TWN":"這應該是用來吸引客人目光的誘餌，實際上根本抓不起來。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그래서, 못해?","JPN":"それで、できぬのか？","ENG":"So? You can’t do it?","TWN":"所以呢，你辦不到嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님께서 원하신다면야. 이 도마에게 맡겨주시길.","JPN":"我が主のお望みとあれば、このドマにお任せを。","ENG":"Your wishes are my command, Mistress. Please leave it to me.","TWN":"只要是主人想要的，儘管包在多馬身上。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"제아무리 뽑기 힘든 상품이라도 노릴 수 있는 약점은 존재하는 법.","JPN":"いかに入手困難な商品であろうとも、隙は必ず存在するものです。","ENG":"No matter how tough the target might be... there always lies a weak spot.","TWN":"再怎麼難抓的商品也有它的弱點。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"가령 이런 눈꺼풀 같은 홈부분에 집게를 걸친다면…","JPN":"例えば、この瞼のような部分にアームをひっかければ……","ENG":"For instance, the eyelid could be an excellent place to hook the claw...","TWN":"譬如說用爪子去鉤眼皮的部分…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"잠깐… 거긴…","JPN":"ちょっと……そこは……","ENG":"Wait... Not there...","TWN":"等一下…那裡…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"크와아아앗!!!!","JPN":"クアアアアッ！！！！","ENG":"Gahhhhh!!!","TWN":"啊啊啊啊啊！！！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"아, 깜짝이야.","JPN":"驚いたな。","ENG":"Oh my.","TWN":"唉唷，嚇我一跳。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이 자식! 감히 내 눈을 찔러?! 짓밟아주지!","JPN":"てめぇ！　よくもアタシの目を突っついてくれたな！　踏みつぶしてやる！","ENG":"You idiot! How dare you poke my eye! I’ll crush you!","TWN":"你這臭小子！想鉤我的眼皮？！當心我打爆你！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭐야? 이거 왜 안 깨져?","JPN":"何だ？　これ、なんで割れないんだ？","ENG":"Huh? Why won’t this break?","TWN":"搞什麼？怎麼不會破？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 그 기계를 부수고 나오는 건 어려울 겁니다.","JPN":"ふふ、その機械を壊して出てくるのは難しいでしょう。","ENG":"Ha ha, it won’t be easy trying to break through that glass.","TWN":"呵呵，你想破壞這台機器從裡面爬出來應該有困難。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이 오락실의 단골인 저희 주인님께서 게임에서 지고 화가 날 때마다 기물을 부수다보니, 가게주인분이 세계최고의 방벽제조사인 ‘더 월’에 의뢰를 맡겨 제작한 특수유리니까요.","JPN":"このゲームセンターの常連である我が主が、ゲームに負けるたびに怒って機械を壊したせいで、店主が世界一の防壁製造会社「ザ・ウォール」に依頼して作らせた特殊ガラスですから。","ENG":"As a regular customer of this arcade, my mistress used to break the machines whenever she would lose or fail. So the owner of the shop decided to make special orders to \\"The Wall\\", the leading company for barricades and bulletproof glass.","TWN":"我們主人可是這間遊戲場的常客，每次主人輸掉遊戲發火時都會攻擊機台，但店家說這是委託世界頂尖護盾製造商‘壁壘’製作的特殊玻璃。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흥, 그래봐야 내가 마음만 먹으면 한 주먹에 부술 수 있거든?","JPN":"ふん、妾がその気になればこんなもの拳ひとつで壊せるぞ。","ENG":"Hmph, it’ll still take me a single blow to shatter this glass into pieces.","TWN":"哼，要是我認真起來的話，一拳就能打爆它好嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론입니다. 주인님께서 진심을 다 한다면 이 세계를 멸망시키는 것조차 간단한 일이죠.","JPN":"もちろんです。ご主人様が本気を出されたら、この世界を滅ぼすことさえ容易いことでしょう。","ENG":"Of course, Mistress. Destroying the world would be easy as cake if it is something you deeply wish for.","TWN":"那是當然的，只要主人下定決心，彈指間就可以毀掉這個世界。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"하! 네가 세계를 멸망시킨다고? 뭐 대단한 능력이라도 가지고 있는 모양이지?","JPN":"は！　てめえが世界を滅ぼす？　すごい能力でも持ってるのか？","ENG":"Hah! You? Destroying the world? Sounds like you don’t know what you’re capable of.","TWN":"哈！你要毀掉世界？不就很厲害的樣子？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"호오? 감히 날 도발하다니. 재밌는 녀석이구나.","JPN":"ほう？　妾を挑発するとは。面白いやつじゃな。","ENG":"Oh? Are you dare taunt me? That's interesting.","TWN":"喔呵？竟然敢挑釁我，有趣的傢伙。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"큭큭, 난 센 척하는 녀석이 있으면 봐주곤 못 넘기는 체질이라 말이야.","JPN":"ククッ、アタシは強いふりするやつを見ていられない体質なんでな。","ENG":"Hah hah, I’m the type of person who can’t stand arrogant brats like you.","TWN":"呵呵，我天生就是看那種虛張聲勢的人不爽。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"자신 있으면 어디 한 번 그 실력 좀 구경해볼까?","JPN":"自信があるんならその実力とやらを見せてもらおうじゃないか。","ENG":"If you’re so confident about your powers, why not show me?","TWN":"要是真這麼厲害的話，那就讓我見識一下吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"어린 것이 배짱 한 번 좋구나.","JPN":"若僧が、いい度胸じゃ。","ENG":"You’re brave, kid. I give you that.","TWN":"這傢伙膽識不錯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"좋다. 오늘은 기분이 좋으니, 네놈의 결투 신청을 흔쾌히 받아주지.","JPN":"よかろう。今日は機嫌がいい、其方の決闘の申し出は快く受けてやろう。","ENG":"Very well. Since I am in a good mood today, I shall accept your offer and fight.","TWN":"好吧，我今天心情好，就爽快收下你的戰帖吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"음…? 뭐지? 이 심상치 않은 기운은…?","JPN":"うむ……？　何だ？　この凄まじい気は……？","ENG":"Mm...? What is this menacing energy...?","TWN":"嗯…？怎麼回事？氛圍不太尋常…？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"시종, 이 몸의 전용의자를 가져오거라.","JPN":"僕よ、妾の椅子を持ってまいれ。","ENG":"Servant, fetch me my chair.","TWN":"僕人，把我的專屬座椅拿來！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"후후, 금방 대령하겠습니다.","JPN":"ふふ、すぐにお持ちいたします。","ENG":"Ha ha, as you wish, Mistress.","TWN":"呵呵，立刻準備。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"간만에 흥미진진한 대결이 되겠군요.","JPN":"久々に興味深い対決になりそうですね。","ENG":"This will be something worth watching in a while.","TWN":"好久沒看到精采的對決囉。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"크윽…?!","JPN":"くうっ……！？","ENG":"Krrgh...?!","TWN":"呃呃…？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"아하하하!","JPN":"あははは！","ENG":"Ah hah hah hah!","TWN":"哇哈哈哈！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"너 같은 녀석이 우주대악당이라고? 분수도 모르면서 감히 이 몸에게 도전장을 내밀다니. 가소롭구나.","JPN":"貴様のようなやつが宇宙大悪党じゃと？　身の程も知らずこの妾に挑戦するとは。笑わせる。","ENG":"You call yourself the Atrocious Space Supervillain? With those noob controls? Pathetic.","TWN":"就你這點料也敢稱為宇宙大反派？不知好歹的傢伙還敢對我下戰帖，真是可笑。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"}}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"칫… 정복 첫날부터 이런 강적을 만나다니.","JPN":"チッ……征服初日からこんな強敵に出会うなんて。","ENG":"Tch... Just my luck running into a formidable foe on my first day of world domination.","TWN":"嘖…征服的第一天竟然就遇到強敵。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이대로 질 순 없지! 다시 승부하자!","JPN":"このまま負けてられない！　もう一度勝負しようぜ！","ENG":"I can’t give up just yet! I challenge you again!","TWN":"我不能輸！再比一局！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"크아아악!","JPN":"ぐあぁぁっ！","ENG":"Grooar!","TWN":"呃呃呃！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흥, 싱겁구나. 발끝에도 못 미치는 수준이라니.","JPN":"ふん、つまらぬ。足元にも及ばぬ実力じゃな。","ENG":"Hmph, not even close. Try harder.","TWN":"哼，真無聊，你根本看不到我的車尾燈。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"자, 이제 마무리를 지어볼까?","JPN":"さて、これでお終いにしようではないか。","ENG":"Now, let’s put an end to this boring fight.","TWN":"我要結束囉？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"대체 뭐하는 괴물이야? 이 말도 안 되는 반응 속도는 또 뭐고?","JPN":"いったいどんなバケモンなんだよ？　この反応速度、あり得ないだろ？","ENG":"That monster... What are those insane reflexes?","TWN":"她到底是什麼怪物？反應速度快得要命是怎樣？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"네 녀석이 무식하게 공격만 해서 계속 반격기에 당하고 있지 않느냐! 잡기! 잡기를 써라!","JPN":"貴様が愚直な攻撃ばかりしているから返し技を食らうのだ！　投げ技だ！　投げ技を使え！","ENG":"You're getting countered all the time because all you do is to attack! Grab! Use grab!","TWN":"誰叫你只會一味地攻擊，當然會被反擊！要抓她啦！抓她！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"시끄러! 나도 알거든!","JPN":"うるさい！　アタシだってわかってるよ！","ENG":"Shut up! I know that!","TWN":"廢話！誰不知道！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"크윽…! 내가 잡기에 당하다니?!","JPN":"くっ……！　アタシが投げ技にやられるなんて！？","ENG":"Krrrgh...! I got grabbed?!","TWN":"呃…！結果是我被抓？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"한심하구나. 그렇게 자신만만하게 도전 해놓고 처참하게 지다니.","JPN":"情けない。あれほど自信満々に挑戦しておいて、惨めに負けるとはな。","ENG":"Pitiful. Your confidence has plummeted to the ground.","TWN":"真是沒用，剛剛下戰帖時還那麼神氣，結果慘敗。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"너도 1라운드도 못 따낸 건 마찬가지잖아!","JPN":"1ラウンドも勝てなかったのはお互い様だろうが！","ENG":"Hey, you didn’t win any single round as well! So we’re even!","TWN":"你還不是連一局都沒贏！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"적어도 난 네 녀석처럼 한 대도 못 때린 채 퍼펙트로 지진 않았단다.","JPN":"少なくとも我は貴様のように一発も当てられず完敗したのではない。","ENG":"At least, I didn't lose with perfect like you.","TWN":"至少我沒像你一樣，一下都沒打到就被剃光頭。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이기지 못하면 그게 뭐가 중요한데?","JPN":"負けは負けだろうが？","ENG":"What’s the point of all that if you don’t win?","TWN":"有什麼差？你還不是沒贏！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"뭐해? 벌써 포기하려고?","JPN":"何をしておる？　もう諦めるのか？","ENG":"Giving up already?","TWN":"幹嘛？要棄權嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"흥, 고작 이 몸을 몇 번 쓰러트렸다고 해서 우쭐대긴 이르지.","JPN":"ふん、我を何回か倒せたからといってうぬぼれるな。","ENG":"Hmph, winning a few times won’t grant you any glory.","TWN":"哼，不過就贏我幾局，有什麼好囂張的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"야, 우리 동전 다 떨어졌는데?","JPN":"おい、小銭がもうねえぞ？","ENG":"Hey, we ran out of coins.","TWN":"喂，我們的零錢都花光咧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"뭣이?!","JPN":"何！？","ENG":"What?!","TWN":"什麼？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"악당이란 타이틀은 장식이냐? 길 가던 직장인들 지갑이라도 털어보거라!","JPN":"悪党という看板はただの飾りか？　道行くサラリーマンの財布でもかっさらうのだ！","ENG":"You’re a villain, are you not? Go rob some bypassing workers or something!","TWN":"你反派是當假的嗎？不會隨便抓個路人搶劫他的錢包嗎！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"오! 그런 방법이 있었지!","JPN":"お！　そういう方法があったな！","ENG":"Oh! You’re right!","TWN":"對欸！還有這個方法！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어이! 네 녀석! 지갑에 든 돈을 내놔!","JPN":"おい！　そこの雑魚！　財布の金を出せ！","ENG":"Hey! You! Hand over your money!","TWN":"喂！小子！把錢包裡的錢交出來！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L32_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"이야, 죄송해요. 어제 스승님 회식비를 대신 내느라 탈탈 털려서 말이죠.","JPN":"いやぁ、すみません。昨日師匠の代わりに会食代を払ったので、一文無しなんですよ。","ENG":"Oh, my apologies. I’m broke because I had to pay for Master’s dinner.","TWN":"哎呀，真抱歉，我昨天代墊師傅的聚餐費，現在錢包都空咧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뒤져서 나오면 동전 하나에 한 대씩이다!","JPN":"ポケットに１円玉でも入ってたら、１円につき一発だからな！","ENG":"It’s gonna be one blow for each coin we get out of you!","TWN":"要是被我搜到零錢，一塊打一下！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"동전…?","JPN":"１円……？","ENG":"Coin...?","TWN":"零錢…？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"아, 전 또 큰돈을 원하는 강도분인 줄 알았지 뭐예요?","JPN":"ああ、てっきり大金が欲しい強盗の方かと思いました。","ENG":"Oh, I thought you wanted a large amount of money.","TWN":"喔～我還以為是要搶劫大筆的強盜呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"동전이라면 몇 개 남은 게 있습니다. 여기요.","JPN":"小銭ならいくらか持ってますよ。どうぞ。","ENG":"If it’s coins you’re asking for, here. I have a few left.","TWN":"零錢的話我這是有一點，拿去吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"아… 고마워.","JPN":"ああ……ありがとう。","ENG":"Oh... Thanks.","TWN":"喔…謝謝。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"인간을 갈취하라고 했더니 구걸따윌 하고 있는 것이냐? 정말이지 악당의 수치로구나.","JPN":"恐喝しろと言ったのに物乞いをしてるのか？　まったく、悪党の恥だな。","ENG":"I told you to rob humans, not beg. You truly are a disgrace to us villains.","TWN":"我叫你搶劫人類，結果你卻去向人類乞討？你真的是反派之恥！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그래서 얼마나 받았지?","JPN":"それで、いくらもらったんだ？","ENG":"So how much did you get?","TWN":"怎麼樣？拿到多少？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이 정도면 다섯 판은 더 할 수 있겠는데?","JPN":"このくらいならあと5回はやれそうだぞ。","ENG":"I think this would get us about five more sets!","TWN":"這些錢應該可以再玩五局吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"오, 격투게임이네요? 저도 구경해도 되죠?","JPN":"おお、格闘ゲームですね。僕も見てていいですか？","ENG":"Oh, a fighting game? May I watch?","TWN":"喔，是格鬥遊戲欸，我可以在旁邊看吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"흥, 물론이지. 이번에야말로 이길 테니 네 녀석도 잘 봐두라고.","JPN":"ふん、もちろんだ。今度こそ勝つからてめえもよく見とけ。","ENG":"Hmph, of course. I’ll win for sure this time. You just wait and see.","TWN":"哼，當然，這次我一定會贏的，睜大你的眼睛看好！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"겨우 다섯 판으로? 어차피 또 질 게 뻔한데 그 정도로 연습이나 되겠어?","JPN":"たった5回じゃと？　どうせ負けるだろうに、その程度では練習にもならぬわ。","ENG":"With only five rounds? I doubt that’ll do you any good. You’re going to lose anyway.","TWN":"才五局？反正你一定又會輸，就當作是練習吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭐야?!","JPN":"何だと！？","ENG":"Whaaat?!","TWN":"什麼？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"너네, 기본기는 충실한데 테크닉이 영 부족해.","JPN":"其方たち、基本スキルは十分じゃがテクニックがまったく足りぬ。","ENG":"You two, your controls are good but you lack technique.","TWN":"你這傢伙，基本功很扎實，只是技巧不足。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"이대로 계속하면 나도 시시하니까, 내가 좀 가르쳐 줄까?","JPN":"このまま続けても退屈じゃ。妾が教えてやろうか？","ENG":"Why don’t I teach you as we go? Winning all the time isn’t fun, you know.","TWN":"再贏下去也沒意思，要我教你兩招嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"응…? 그게 정말이냐?","JPN":"む……？　それは本当か？","ENG":"Hmm...? Do you mean it?","TWN":"嗯…？真的嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그래, 마침 달콤한 것도 당기던 참이니 자리를 옮기는 게 좋겠구나.","JPN":"うむ、ちょうど甘いものが欲しかったところじゃ。場所を移そう。","ENG":"Yes, I was craving something sweet anyway... Let us move to another place.","TWN":"嗯嗯，正好我想吃甜點，就移動一下位置吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…하하하! 그거 골때리는구만!","JPN":"……ハハハ！　そりゃとんでもないな！","ENG":"...Ha ha ha! You must be joking!","TWN":"…哈哈哈！笑死！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그래서, 네 상사는 경찰을 보자마자 그대로 창문을 깨고 달아났단 말이지?","JPN":"それで、てめえの上司は警察を見るなりそのまま窓を割って逃げたのか？","ENG":"So, your boss fled through the window as soon as the cops came in?","TWN":"你說你上司一看到警察就破窗而出嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"뭐, 그때는 저 혼자 시말서를 쓰느라 고생했지만 돌이켜보면 다 추억이죠.","JPN":"まあ、その時は僕一人で始末書を書くのに苦労したんですけど、今考えるといい思い出ですよ。","ENG":"Yes, well... I went through a lot of trouble writing the letter of explanation on my own, but it’s all passed now.","TWN":"那時候我寫悔過書寫得多辛苦，不過現在回想起來都是回憶呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그런 상사를 두면 회사를 관둘 법도 한데, 저 녀석도 참 보살이라니까.","JPN":"そういう上司がいると会社をやめてもおかしくなかろうに、其方もたいがい人がいい。","ENG":"With a boss like that, I would have quit my job long ago. He has a heart of gold, that boy.","TWN":"有那種上司應該要辭職吧，你這傢伙還真是不記仇。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"하하, 스승님이 겉으론 무정해 보여도 정이 많으신 분이라서요.","JPN":"はは、師匠は無情に見えても、情が深い方なんで。","ENG":"Ha ha, Master might sound cold and heartless, but she is actually very caring.","TWN":"哈哈，師傅雖然看似無情，但其實很重感情的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"아마 제가 관두고 사라진다면 우주 끝까지라도 절 잡으러 오실 겁니다.","JPN":"多分僕が仕事を辞めて消えたら、宇宙の果てまで捕まえに来ますよ。","ENG":"If I were to quit my job and disappear, she would probably come looking for me all over space.","TWN":"要是我辭職消失的話，就算是天涯海角她也會把我揪回的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그건 좀 무서운데…?","JPN":"それはちょっと怖いな……","ENG":"That’s kind of creepy...","TWN":"那好像有點恐怖欸…？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"듣자 하니 네 녀석들도 우리 악당 못지 않게 참 파란만장하게 살았구나.","JPN":"聞けば、お前らも我々悪党に負けず劣らず波瀾万丈な人生を生きて来たのだな。","ENG":"From what I hear, you've also been through quite a lot, like us.","TWN":"這樣聽起來，你們活得也不比我們反派輕鬆呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"회사생활이라는 것도 제법 재밌어 보이는 걸?","JPN":"会社生活というものも結構面白そうではないか。","ENG":"Working at a company sounds rather interesting.","TWN":"職場生活感覺也蠻有趣的？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그럼~ 악당처럼 보험도 못 들고 수익이 불안정한 직종은 별로 인기가 없지.","JPN":"そうじゃ～悪党のように保険もなく、収益が不安定な職種はあまりモテぬ。","ENG":"Of course! There aren't a lot of jobs that are as unstable and dangerous as being a villain.","TWN":"那當然～反派這個職業既沒有保險，收入又不穩定，當然沒什麼人想從事。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"게임을 좋아한다면 이 참에 너희도 입사지원서나 내보는 건 어떠냐?","JPN":"ゲーム好きというのなら、この際其方たちも履歴書を出してみてはどうじゃ？","ENG":"If you are into games, why don’t you both submit a resume?","TWN":"既然你們喜歡玩遊戲，不如就趁這個機會遞交入職申請書吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"맞습니다. 물가 오르는 속도가 제 연봉인상보다 빠르다는 점만 빼면 안정적인 직장을 갖는 게 최고이거든요.","JPN":"そうですよ。物価上昇の速度が僕の昇給よりも早いのがネックですが、安定した職が一番ですからね。","ENG":"She’s right. Aside from the fact that inflation is more rapid than my salary raise, it’s nice having a job with stable income.","TWN":"沒錯，雖然薪水漲的速度比不上物價上漲的速度， 但排除這點，有個穩定的工作還是比較好的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"괜찮네. 이 참에 나도 회사에 취업이나 해볼까?","JPN":"いいな。アタシも会社に就職してみるか？","ENG":"That sounds pretty good. Maybe I should seriously consider applying for a job at a company.","TWN":"好像不錯欸，我也趁機找個工作吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"생각 한 번 단순하구나. 네놈의 망나니 기질을 직장에서 감당할 수 있을 것 같으냐?","JPN":"単純でいいな。貴様のごろつき気質に職場が耐えられると思うのか？","ENG":"Such a simple minded child. Do you really think your workplace will be able to handle your insane impulses?","TWN":"想得簡單，你這傢伙天生做反派的料，你有辦法承受職場生活嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"으음… 그것도 맞는 말이야.","JPN":"うーむ……それもそうだな。","ENG":"Mm... You do have a point.","TWN":"呃…你說的也沒錯。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"생각보다 이성적으로 납득하시네요.","JPN":"思ったより理性的に納得するんですね。","ENG":"You accept it rather calmly than I imagined.","TWN":"你還真好說服。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"사실, 요즘 들어 악당짓을 하면서도 예전만큼 보람차지 않더라고.","JPN":"実はな、最近悪党やっても昔のようにやりがいを感じられなくてさ。","ENG":"To be honest, being a villain doesn’t bring as much joy to me as it used to.","TWN":"不瞞大家說，我最近在幹壞事時，已經沒有像過去那種滿足感。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"돌이켜보면 세간에 악명을 떨치는 것 말고는 남긴 것 하나 없었고 말이야.","JPN":"振り返ってみると世間に悪名を轟かせること以外に残したもんもなかったし。","ENG":"I never had any achievements apart from being infamous.","TWN":"驀然回首，留下的只有臭名。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"네 녀석이 그런 깊은 생각을 하고 있었다니, 의외로구나.","JPN":"貴様がそんなことを考えていたなんて、意外だな。","ENG":"I couldn't expect to hear someone like you having those kinds of thoughts.","TWN":"沒想到你的心思竟然有這麼深。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"넌 정말로 한결같이 긁어대네.","JPN":"てめえは本当ひたすらウザいな。","ENG":"You’re as annoying as always, aren’t you?","TWN":"你真的是毒舌欸。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"흐음…","JPN":"ふーむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그럼 다시 오락실로 돌아가볼까?","JPN":"それでは、またゲームセンターに戻るとするか。","ENG":"Should we go back to the arcade, then?","TWN":"那我們再回到遊戲場吧？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"갑자기…? 네가 우리보다 강한 건 이미 충분히 증명하지 않았어?","JPN":"いきなり……？　てめえがアタシたちより強いってのはもう十分証明しただろ？","ENG":"Why all of a sudden...? We get it. You’re stronger than us.","TWN":"這麼突然…？不是已經充分證明你比我們厲害嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"결투 때문이 아니다.","JPN":"決闘のためではない。","ENG":"I’m not going to fight you.","TWN":"回去不是要決鬥。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"네놈이 하려던 인형 뽑기, 아직 마무리 짓지 못했잖아?","JPN":"其方がやろうとしていたクレーンゲーム、まだ終わってなかろう？","ENG":"You still haven’t got that doll you wanted, have you?","TWN":"你剛不是想抓娃娃還沒抓到嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"조금만 더 왼쪽으로…! 왼쪽을 노리거라!","JPN":"もう少し左……！　左を狙いなさい！","ENG":"A little bit more to the left...! The left, I said!","TWN":"再左邊一點…！瞄準左邊！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"지금이라도 더 작은 인형을 노리는 편이 좋지 않을까요?","JPN":"今からでももっと小さいぬいぐるみを狙った方がいいんじゃないですか？","ENG":"Don’t you think it’ll be wiser to aim for a smaller doll?","TWN":"是不是改抓小一點的比較好？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"시끄러워. 조종하는 건 나거든?","JPN":"うるさい。コントロールしてるのはアタシなんだよ。","ENG":"Shut up! I’m the one controlling the claw!","TWN":"你們好吵，現在是我在控制操縱桿好嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"큭… 이번이 마지막 동전이라고. 제발 좀 뽑혀라.","JPN":"くっ……これで最後のコインだぞ。頼むから出てくれ。","ENG":"Krrgh... This is my last coin. Please, work!","TWN":"呃…這是最後的零錢，拜託一定要抓到！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"잡았다!","JPN":"掴んだ！","ENG":"She did it!","TWN":"有了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"오오…?","JPN":"おお……？","ENG":"Oh...?","TWN":"喔喔…？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"좋아! 그대로 조금만 더!","JPN":"よっし！　そのままもうちょっと！","ENG":"Good! Just a little more!","TWN":"很好！就這樣再！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SERIOUS"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_BACK_FOOLSDAY","text":{"KOREA":"됐다! 내가 성공했다고, 오로치!","JPN":"やった！　成功したぞ、オロチ！","ENG":"I did it! Orochi, I made it!","TWN":"抓到了！我成功了，大蛇！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"흥… 어울리지 않게 고작 인형 하나로 기뻐하긴.","JPN":"ふん……らしくもなく、ぬいぐるみ一つで喜ぶとは。","ENG":"Hmph... All that racket for a lousy doll.","TWN":"哼…抓到這麼小的娃娃還那麼開心。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"큰돈 주고 뽑았으니 칠칠 맞게 잃어버리지나 마라.","JPN":"大金をはたいて取ったんだから、うっかりなくすな。","ENG":"Just make sure you don’t lose it. You paid a fortune for it.","TWN":"花這麼多錢才抓到的，你可別弄丟了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_BACK_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"이야, 결국 마지막에 성공할 줄이야. 축하드려요.","JPN":"いやぁ、結局最後に成功するなんて。おめでとうございます。","ENG":"Wow, you got it with your final shot! Congratulations.","TWN":"哇，我就知道你一定會成功，恭喜你。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"하하… 하하하…","JPN":"ハハ……ハハハ……","ENG":"Hah hah... Hah hah hah...","TWN":"哈哈…哈哈哈…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"그래서, 지금 기분은 어떠냐?","JPN":"それで、今の気分はどうじゃ？","ENG":"So, how do you feel right now?","TWN":"所以呢，你現在心情如何？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…뭐? 지금 기분?","JPN":"……は？　今の気分？","ENG":"...What? How do I feel?","TWN":"…什麼？現在的心情？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭔가 낯설기는 한데… 나쁘진 않은 느낌이네.","JPN":"なんか慣れてないけど……悪くはない感じだな。","ENG":"It’s a kind of strange feeling... But in a good way.","TWN":"好陌生的感覺…不過感覺不錯！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"보람이란, 원하는 것을 규칙에 따라 쟁취했을 때 비로소 온전히 누릴 수 있는 것이지.","JPN":"やりがいとは、規則に従いつつ欲しいものを勝ち取って初めて感じられるものじゃ。","ENG":"The feeling of accomplishment is only earned when you get what you want while following the rules.","TWN":"所謂的滿足，是你用正當手法爭取到你想要的東西時，才能夠完全地享受到。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"기계 안으로 들어가 훔치지 않고, 그 거지같은 집게로 결국 인형을 뽑은 것처럼 말이다.","JPN":"機械の中に潜り込んで盗む代わりに、あのアームで最終的にぬいぐるみを取ったようにのう。","ENG":"Just like how you got the doll from controlling the claw machine, instead of breaking it.","TWN":"就像你現在不是爬到機台裡去偷，而是用那個破爛爪子抓到娃娃的感覺一樣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","text":{"KOREA":"저희는 이만 집으로 돌아갈 건데, 두 분은 정말 괜찮으시겠어요?","JPN":"僕たちはもう帰りますけど、二人は本当に大丈夫なんですか？","ENG":"We will be heading home now. Are you two going to be all right?","TWN":"我們要回去囉，你們二位真的沒問題吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOO_SHI_YOON_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"걱정 말고 가거라. 우린 기다리는 동료가 있으니까.","JPN":"心配せず行くがいい。我々は仲間を待っているのだからな。","ENG":"Do not worry about us. We are waiting for a friend.","TWN":"儘管回去吧，我們還要等一個人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"마음 내키면 언제든 연락해. 면접은 보게 해줄 테니.","JPN":"気が向いたらいつでも連絡するのじゃ。面接を受けられるようにしてやろう。","ENG":"If you feel like applying, let me know. I’ll let you take the interview.","TWN":"有意願的話隨時聯絡我，我可以安排面試。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그래, 다음 번에 만나면 오늘의 패배는 반드시 갚아주지.","JPN":"ああ、次に会ったら今日の借りは必ず返してやるよ。","ENG":"Very well. Next time we meet, I'm getting my revenge.","TWN":"沒問題，下次再見面時，我一定會報仇的！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_NPC_FOOLSDAY_NULL","text":{"KOREA":"…가자, 시종.","JPN":"……行こう、僕よ。","ENG":"...Let’s go, servant.","TWN":"…走吧，僕人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"알겠습니다, 주인님.","JPN":"承知いたしました、ご主人様。","ENG":"Yes, Mistress.","TWN":"是的，主人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"시종이란 녀석은 목소리만 들리고 끝까지 눈에 안 보이는구나.","JPN":"僕というやつは最後まで声だけで、顔は見せないのだな。","ENG":"That servant never shows himself, does he? All I can hear is his voice.","TWN":"那個叫僕人的傢伙，根本從頭到尾只聞其聲不見其人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"목소리는 내 취향이었는데 말이지.","JPN":"声は我の好みだったのだが。","ENG":"His voice was to my taste.","TWN":"不過他的聲音是我的菜。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그 인형이 그렇게 마음에 드느냐?","JPN":"そんなにそのぬいぐるみが気に入ったのか？","ENG":"Do you like the doll that much?","TWN":"你這麼喜歡那個娃娃喔？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"어.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그런데 말이야.","JPN":"でもさ。","ENG":"But...","TWN":"不過，"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그렇게 열심히 뽑지 않았다면, 이 정도로 마음에 들진 않았을 것 같아.","JPN":"あれほど懸命に取ろうとしてなかったら、こんなに気に入ることはなかったと思う。","ENG":"I don’t think I would have liked it this much if I hadn’t put in all the hard work.","TWN":"要是沒有剛才辛苦的過程，也不會這麼喜歡吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"흥… 사내대장부 같이 생겨선, 아주 감수성 넘치는 소녀가 따로 없구나.","JPN":"ふん……屈強な男のようにしているが、実は感性豊かな少女なんだな。","ENG":"Hmph... With looking like a tough guy, you talk like a frail innocent damsel.","TWN":"哼…長得那麼Man，沒想到是個心思細膩的少女呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"뭐야. 나 빼놓고 둘이 데이트하고 있었나?","JPN":"なんだよ。俺をのけ者にして二人でデートしてたのか？","ENG":"What’s going on? Are you two having fun without me?","TWN":"搞什麼，你們是背著我約會嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"당연히 서로 물어뜯고 있을 줄 알았더니, 두 사람 사이가 좋아졌나봐?","JPN":"当然お互い言い争ってるだろうと思ったけど、仲良くなれたようだね。","ENG":"I thought you two would be biting each other’s heads off by now. But it looks like you two become close?","TWN":"我還以為你們二個會吵翻天，怎麼好像感情變好啦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"딱히 변한 건 없다만?","JPN":"別に変わったことはないのだが？","ENG":"Nothing changed much, really.","TWN":"哪有變？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"그러는 넌 수갑을 아직도 풀지 못한 모양이구나.","JPN":"そういう貴様はまだ手錠を外せていないようだな。","ENG":"Meanwhile you're still there, handcuffed.","TWN":"倒是你，你的手銬好像還沒解開呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"빌어먹을 우주수갑… 너무 튼튼해서 이 동네 엔지니어도 감당을 못 하더라고.","JPN":"クソったれな宇宙手錠……頑丈すぎてこの街のエンジニアも手が付けられなかったんだ。","ENG":"These stupid space handcuffs... They’re so sturdy that even the town’s engineer couldn’t do anything.","TWN":"該死的宇宙手銬…牢固到這附近的工程師也拿它沒辦法。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"그래도, 돌아갈 방법은 찾았어. 포탈 수리에 필요한 부품을 구했거든.","JPN":"でも、戻る方法は見つけたよ。ワープ装置の修理に必要な部品があったからね。","ENG":"Still, I found a way to get home. I’ve obtained all the parts needed to fix the portal machine.","TWN":"不過至少我有找到回去的方法，還弄來修理傳送門需要的零件。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그럼, 이쪽 세계와는 작별인 건가?","JPN":"じゃあ、こっちの世界とはおさらばなのか？","ENG":"I guess we’re gonna have to say goodbye to this world.","TWN":"意思是，我們要跟這個世界告別了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"그렇게 되겠지.","JPN":"そうなるな。","ENG":"I guess so.","TWN":"是吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"아쉬워? 반나절 사이에 세계에 정이라도 붙이셨나?","JPN":"名残惜しい？　半日でこの世界に情が湧いたのか？","ENG":"Why the lone face? You feel attached already?","TWN":"捨不得嗎？才半天時間不見，你就愛上這個世界啦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그런 건 아니지만… 조금은 더 머물러도 괜찮을 것 같달까…?","JPN":"そんなわけじゃないけど……もうちょっといても大丈夫じゃないかなーって……","ENG":"Not really... But maybe we could stay a bit longer...?","TWN":"不是這樣…只是覺得多待一會兒好像也沒關係…？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"이유는?","JPN":"その理由は？","ENG":"And why’s that?","TWN":"理由是？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이건 그러니까… 그…","JPN":"それはえーっと……その……","ENG":"Because... you know...","TWN":"理由是…是…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"복수를 해줘야 할 상대가 생겼다.","JPN":"復讐をすべき相手ができた。","ENG":"We have someone to take vengeance on.","TWN":"因為現在有要報仇的對象。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"우리 같은 자존심 높은 악당이 지고 살 수는 없지 않겠느냐?","JPN":"我々のようなプライド高き悪党が負けていられないではないか。","ENG":"We’re dignified villains. Surely we can’t let a grudge pass, no?","TWN":"像我們這種愛面子的反派怎麼可以服輸？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"마, 맞아! 오늘 꽤 강한 녀석을 만났는데 아쉽게 져버렸거든!","JPN":"そ、そうだぞ！　今日結構強いやつに会ったんだけど、残念ながら負けちゃってな！","ENG":"S-she’s right! We met someone quite hard to beat, it was such a close call!","TWN":"沒…沒錯！今天遇到高手，雖然我不幸落敗，"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"하지만 마지막에 이기는 게 진짜 승자인 법이니까! 무슨 말인지 알지?","JPN":"だけど、最後に勝った方が本物の勝者だからさ！　この意味わかるか？","ENG":"But the last one standing becomes the winner! You know what I’m saying, right?","TWN":"不過贏得最終勝利的人才是真正的贏家！你懂我意思吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"흐음…","JPN":"ふーん……","ENG":"Hmm...","TWN":"喔喔…"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"요지는 이해했어. 어차피 당장은 돌아가기 힘들어졌으니까.","JPN":"要旨は理解した。どうせ今すぐには戻れなくなったからな。","ENG":"I get your point. We’re not going back immediately anyway.","TWN":"明白，反正現在也很難回去。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"뭐…? 그게 무슨 소리야?","JPN":"は……？　どういうことだ？","ENG":"Huh...? What do you mean?","TWN":"什麼…？你那是什麼意思？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"차원 포탈을 수리하려면 적어도 1년은 걸려.","JPN":"ワープ装置を直すには、少なくとも1年はかかる。","ENG":"It takes at least a year to fix the dimensional portal.","TWN":"修理次元傳送門起碼要花一年的時間。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"오오, 1년씩이나?","JPN":"おお、1年も？","ENG":"Oh, a whole year?","TWN":"喔喔，一年喔？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"흐음- 제법 걸리는구나?","JPN":"ふむ、結構かかるものだな。","ENG":"Hmm... A year sounds rather long.","TWN":"哼-還真久？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_LAUGH"},"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"뭔데? 너희, 왜 그런 걸로 기뻐하는 거야?","JPN":"何？　お前ら、なんでそんなことで喜ぶんだよ？","ENG":"What is it? Why do you two look so happy?","TWN":"是怎樣？為什麼你們一副很開心的樣子？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"이렇게 된 이상 어쩔 수 없이 직장이라도 구해서 돈을 벌어야겠구나.","JPN":"こうなっては、仕方なく職場でも探して金を稼ぐべきだな。","ENG":"I suppose we have no choice but to apply for jobs to make money.","TWN":"既然如此，那只好勉為其難找個工作來賺錢餬口囉。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"이야, 어쩔 수 없구만.","JPN":"いやあ、仕方ないなあ。","ENG":"Ohh, how unfortunate.","TWN":"哎呀，真的是勉為其難。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_PRIDE"}}}},{"id":"L20_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"세계정복이니 뭐니 하며 떠들어댈 줄 알았더니, 그건 상상도 못한 대답이군.","JPN":"世界征服だのなんだの騒ぐかと思ったら、想像もしなかった答えだね。","ENG":"I thought it would be gibberish similar to world domination or something... That was unexpected.","TWN":"之前是誰說什麼要征服世界的，這是什麼神展開？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"악당이 뭣하러 직장을 구해? 그냥 남들 주머니를 털어버리면 되는 거 아닌가?","JPN":"悪党がなんで職場を探すんだよ。別に人の懐からいただけばいいだろ？","ENG":"Why would villains want to get a job? You could just rob others.","TWN":"反派還找什麼工作？直接搶劫別人的口袋就好啦？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"그건 안되지! 그렇게 쉽게 빼앗으면 보람이 없다고!","JPN":"それはダメだ！　そう簡単に奪ったらやりがいがないだろ！","ENG":"No taking! Where’s the fun in that?","TWN":"那怎麼行！得之不易才顯得珍貴！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"빼앗는 것도 좋지만, 가끔은 인간들의 문명을 직접 체험해보는 것도 재밌을 것 같아서 말이다.","JPN":"奪うのもいいのだが、たまには人間の文明を直接体験してみることも面白そうでな。","ENG":"Robbery is fine, but I think it'd be nice to experience human culture every now and then.","TWN":"直接行搶也很好，只是偶爾體驗一下人類的文明應該也蠻有趣的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"너희들… 그새 사이비한테 세뇌라도 당했냐? 아니면 도플갱어인가?","JPN":"お前ら……カルト集団に洗脳でもされたのか？　それともドッペルゲンガー？","ENG":"Hey... Were you brainwashed by cults or something? Or are you Doppelgangers?","TWN":"你們…是被誰洗腦嗎？還是你們其實是二重身？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"사이비가 뭔데?","JPN":"カルトって何だ？","ENG":"What’s a cult?","TWN":"洗腦是什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_FOOLSDAY","text":{"KOREA":"도플갱어라는 건 또 무엇이냐?","JPN":"ドッペルゲンガーとはまた何なのだ？","ENG":"What’s a Doppelganger?","TWN":"二重身又是什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_FOOLSDAY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"…내가 알고 있던 얼간이들이 맞군.","JPN":"……俺の知ってるアホたちで間違いないな。","ENG":"...Never mind. It is you after all, idiots.","TWN":"…確實是我認識的那個二傻瓜沒錯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"뭐, 언제 우주경찰이 여기까지 들이닥칠지 모르니 그런 위장 신분을 하나 만들어 두는 것도 괜찮겠지.","JPN":"まあ、いつ宇宙警察がここまで押し寄せてくるかわからないから、そういった偽の身分を作っておくのも悪くない。","ENG":"Since we don’t know when those space cops might come barging in, it would be a good idea to keep a fake identity.","TWN":"好吧，宇宙警察不知道什麼時候會追到這裡來，找個工作偽裝身分也不錯。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COLLECTOR_NPC_NULL_FOOLSDAY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"좋았어! 오늘은 취업기념으로 밥이나 먹자고!","JPN":"よっし！　今日は就職記念に飯にでも行こうぜ！","ENG":"Yes! Let’s eat out to celebrate our new job!","TWN":"好欸！那就去吃飯慶祝找到工作吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_UNIT_FOOLSDAY","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"벌써 결정됐다는 듯이 말하지 마.","JPN":"もう決まった風に言うな。","ENG":"Don’t talk as if you already got a job.","TWN":"不要講得一副已經找到工作的樣子，"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"이력서나 준비해두라고.","JPN":"履歴書から用意しておけ。","ENG":"Talk after you’ve prepared your resume.","TWN":"先準備好你的履歷表吧。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"KNIGHT_REPLACER_UNIT_FOOLSDAY","text":{"KOREA":"응? 이력서가 뭔데?","JPN":"あ？　履歴書って何だよ。","ENG":"Huh? What’s a resume?","TWN":"嗯？履歷表是什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_FOOLSDAY","text":{"KOREA":"하아…","JPN":"はあ……","ENG":"*Sigh*","TWN":"哀…"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};